// Resolve today's date in CST and the current CST hour (0-23). The hour
// is stamped on the ingest payload so the edge function writes the
// snapshot to the right (scrape_date, scrape_hour, agent_name) row in
// intraday_snapshots. Same shape as the ICD intraday workflow.
function nowCST() {
  const now = new Date();
  const central = new Date(now.toLocaleString('en-US', { timeZone: 'America/Chicago' }));
  const date = central.getFullYear() + '-' + String(central.getMonth() + 1).padStart(2, '0') + '-' + String(central.getDate()).padStart(2, '0');
  return { date, hour: central.getHours() };
}
const { date, hour } = nowCST();
return [{ json: { scrape_date: date, scrape_hour: hour } }];

