// Dialpad Stats job reported a terminal failure. Throw so this n8n
// execution is marked FAILED and any failure-workflow alerts fire.
// Avoids silent infinite polling when the upstream is broken.
const payload = $input.first().json || {};
throw new Error(`Dialpad stats job ${payload.request_id || '?'} ended with status=${payload.status || 'UNKNOWN'}.`);

// Defense-in-depth: cap the poll loop at 8 minutes. Dialpad caches
// is_today=true results for 30 min so most jobs return in <1 min.
// Anything past 8 min means upstream is hung; bail loudly so we don't
// pile up stuck n8n executions.
const MAX_MINUTES = 8;
const startedAt = $node['POST /stats (initiate)'].json.created_at
  || $node['Compute Today + Hour (CST)'].json.scrape_date;
const startMs = $execution.startedAt ? new Date($execution.startedAt).getTime() : Date.now();
const elapsedMin = (Date.now() - startMs) / 60000;
if (elapsedMin > MAX_MINUTES) {
  throw new Error(`Dialpad poll loop exceeded ${MAX_MINUTES}min cap (elapsed=${elapsedMin.toFixed(1)}min). Aborting.`);
}
return $input.all();

// Parse the Dialpad calls CSV (export_type=records) and normalize into
// the shape ingest-dialpad-calls expects.
//
// Column names verified against the live Dialpad API on 2026-04-27:
//   call_id            — per-LEG unique id (use this as primary key)
//   master_call_id     — shared across all legs of the same call
//   target_type        — 'user' | 'office' | 'department' | 'call_center'
//   target_id          — id of the target (user_id when target_type='user')
//   name               — human name of the target (e.g. 'Eric Marrs')
//   talk_duration      — talk time in MINUTES (decimal, e.g. 56.61)
//   ringing_duration   — ring time in MINUTES (decimal, e.g. 0.08)
//   direction          — 'inbound' | 'outbound'
//
// IMPORTANT: durations are decimal MINUTES, not seconds. Multiply by 60
// before sending to the edge function (which expects seconds in its DB
// schema). Cross-checked against (date_ended − date_connected) / 1000
// against talk_duration × 60 — matches within ±1s.
//
// We FILTER to target_type === 'user' rows only. The CSV also returns
// office/department/call_center rows for the same calls; counting them
// would multiply talk-time by the number of legs. Only the user row is
// the agent leg we want to attribute.
//
// Each hourly run rebuilds today's full picture (the edge function
// merges aggregates by overwriting the dialpad_* columns), so this is
// idempotent regardless of whether Dialpad returns deltas or cumulative.

const raw = typeof $input.first().json.data === 'string'
  ? $input.first().json.data
  : (typeof $input.first().json.body === 'string' ? $input.first().json.body : '');

const body = raw || $input.first().json.body || '';
if (!body || typeof body !== 'string') {
  return [{ json: { error: true, message: 'No CSV body in download response' } }];
}

function parseCSVLine(line) {
  const out = [];
  let cur = '';
  let inQ = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '"') {
      if (inQ && line[i + 1] === '"') { cur += '"'; i++; }
      else { inQ = !inQ; }
    } else if (ch === ',' && !inQ) {
      out.push(cur);
      cur = '';
    } else {
      cur += ch;
    }
  }
  out.push(cur);
  return out;
}

const lines = body.split(/\r?\n/).filter((l) => l.length > 0);
if (lines.length < 2) {
  return [{ json: { error: true, message: 'CSV has no data rows', lineCount: lines.length } }];
}

const headers = parseCSVLine(lines[0]).map((h) => h.toLowerCase().trim());
const H = (name) => headers.indexOf(name);

function pick(row, aliases) {
  for (const a of aliases) {
    const idx = H(a);
    if (idx >= 0) {
      const v = row[idx];
      if (v !== undefined && v !== '') return v;
    }
  }
  return null;
}

// Decimal minutes -> integer seconds. Returns 0 for null/empty/non-numeric.
function minToSec(v) {
  if (v === null || v === undefined || v === '') return 0;
  const n = parseFloat(String(v));
  if (!Number.isFinite(n) || n <= 0) return 0;
  return Math.round(n * 60);
}

const ctx = $node['Compute Today + Hour (CST)'].json;
const calls = [];
let skippedNonUser = 0;
let skippedNoCallId = 0;

for (let i = 1; i < lines.length; i++) {
  const cells = parseCSVLine(lines[i]);
  if (cells.length < 3) continue;

  // Filter to per-user rows only. Office/department/call_center rows are
  // duplicate legs of the same call and would inflate talk minutes if
  // counted. The edge function's user-id mapping needs target_type='user'
  // anyway.
  const targetType = (pick(cells, ['target_type']) || '').toString().toLowerCase();
  if (targetType !== 'user') { skippedNonUser++; continue; }

  // call_id is the per-leg unique id; master_call_id is shared across
  // legs. We dedupe by call_id at the DB level (UNIQUE constraint).
  const callId = pick(cells, ['call_id']);
  if (!callId) { skippedNoCallId++; continue; }

  const directionRaw = (pick(cells, ['direction', 'call_direction']) || '').toString().toLowerCase();
  const direction = directionRaw.startsWith('out') ? 'outbound'
                   : directionRaw.startsWith('in') ? 'inbound'
                   : null;
  if (!direction) continue;

  const dateStarted = pick(cells, ['date_started', 'date_rang', 'started_at', 'call_start_time']);
  if (!dateStarted) continue;

  const dateConnected = pick(cells, ['date_connected', 'connected_at']);
  const dateEnded = pick(cells, ['date_ended', 'ended_at']);

  // Dialpad CSV: talk_duration + ringing_duration are MINUTES. Convert
  // to seconds so the edge function's INTEGER columns store sane values.
  const talkSec = minToSec(pick(cells, ['talk_duration', 'duration_talk', 'talk_minutes']));
  let ringSec = minToSec(pick(cells, ['ringing_duration', 'ring_duration', 'duration_ring', 'ring_minutes']));

  // Fallback: derive ring from timestamps if column missing/empty.
  if (!ringSec && dateStarted && dateConnected) {
    const a = new Date(dateStarted).getTime();
    const b = new Date(dateConnected).getTime();
    if (Number.isFinite(a) && Number.isFinite(b) && b > a) {
      ringSec = Math.round((b - a) / 1000);
    }
  }

  const totalSec = talkSec + ringSec;

  const targetId = pick(cells, ['target_id', 'user_id']);
  const targetName = pick(cells, ['name', 'target_name', 'user_name']);
  const externalNumber = pick(cells, ['external_number', 'external_phone', 'caller_number']);

  const rawObj = {};
  for (let h = 0; h < headers.length; h++) rawObj[headers[h]] = cells[h];

  calls.push({
    call_id: callId,
    master_call_id: pick(cells, ['master_call_id']) || null,
    direction,
    date_started: dateStarted,
    date_connected: dateConnected || null,
    date_ended: dateEnded || null,
    talk_seconds: talkSec,
    ring_seconds: ringSec,
    total_seconds: totalSec,
    target_id: targetId ? String(targetId) : null,
    target_type: targetType,
    target_name: targetName || null,
    external_number: externalNumber || null,
    was_recorded: pick(cells, ['was_recorded', 'recorded']) === 'true',
    disposition: pick(cells, ['category', 'disposition', 'call_disposition']) || null,
    raw: rawObj
  });
}

return [{ json: {
  scrape_date: ctx.scrape_date,
  scrape_hour: ctx.scrape_hour,
  totalRows: lines.length - 1,
  callCount: calls.length,
  skippedNonUser,
  skippedNoCallId,
  calls
}}];
